class HashTable:
    def __init__(self, capacity=10):
        self.capacity = capacity
        self.table = [[] for _ in range(self.capacity)]

    def _hash(self, key):
        """Hesaplar anahtarın hash değerini ve tablo indeksini döndürür."""
        return hash(key) % self.capacity

    def insert(self, key, value):
        """Anahtar-değer çiftini hash tablosuna ekler veya günceller."""
        index = self._hash(key)
        chain = self.table[index]

        # Anahtar zaten varsa değeri güncelle
        for i, (existing_key, _) in enumerate(chain):
            if existing_key == key:
                chain[i] = (key, value)
                return

        # Anahtar yoksa yeni çifti ekle
        chain.append((key, value))

    def get(self, key):
        """Belirtilen anahtarla ilişkili değeri döndürür. Anahtar bulunamazsa None döndürür."""
        index = self._hash(key)
        chain = self.table[index]

        for existing_key, value in chain:
            if existing_key == key:
                return value

        return None  # Anahtar bulunamadı

    def delete(self, key):
        """Belirtilen anahtara sahip öğeyi tablodan siler. Silme başarılıysa True, aksi takdirde False döndürür."""
        index = self._hash(key)
        chain = self.table[index]

        for i, (existing_key, _) in enumerate(chain):
            if existing_key == key:
                del chain[i]
                return True

        return False  # Anahtar bulunamadı
